import{_ as t,o as a,c as r,ag as n}from"./chunks/framework.DFmy_ALI.js";const p=JSON.parse('{"title":"Secure Flows","description":"","frontmatter":{},"headers":[],"relativePath":"guide/secure-flows.md","filePath":"guide/secure-flows.md"}'),o={name:"guide/secure-flows.md"};function i(s,e,c,d,l,h){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="secure-flows" tabindex="-1">Secure Flows <a class="header-anchor" href="#secure-flows" aria-label="Permalink to &quot;Secure Flows&quot;">​</a></h1><p>Astro SDKs are designed to prevent merchants from accidentally handling bank secrets, customer OTPs, or Open Banking credentials directly.</p><h2 id="ownership-boundaries" tabindex="-1">Ownership boundaries <a class="header-anchor" href="#ownership-boundaries" aria-label="Permalink to &quot;Ownership boundaries&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Responsibility</th><th>Correct owner</th></tr></thead><tbody><tr><td>Merchant API key</td><td>Merchant backend only</td></tr><tr><td>Payment session creation</td><td>Merchant backend</td></tr><tr><td>Customer alias or IBAN entry</td><td>Astro hosted checkout or SDK-controlled surface</td></tr><tr><td>OTP or push approval</td><td>Bank through Astro-hosted authorization</td></tr><tr><td>Open Banking consent decision</td><td>Astro hosted consent screen</td></tr><tr><td>Token exchange</td><td>Merchant or TPP backend</td></tr><tr><td>Final fulfilment</td><td>Merchant backend after signed webhook</td></tr></tbody></table><h2 id="payment-security" tabindex="-1">Payment security <a class="header-anchor" href="#payment-security" aria-label="Permalink to &quot;Payment security&quot;">​</a></h2><p>The merchant backend creates a session and receives a hosted checkout URL. The customer authorizes in Astro. If OTP is selected, the OTP is submitted to Astro and verified through the bank callback interface. If push is selected, the bank controls approval and Astro tracks the state.</p><p>The merchant site must not render its own OTP box for bank authentication. That would train customers to enter bank authorization codes into arbitrary merchant pages.</p><h2 id="subscription-security" tabindex="-1">Subscription security <a class="header-anchor" href="#subscription-security" aria-label="Permalink to &quot;Subscription security&quot;">​</a></h2><p>Recurring mandates require clear customer approval before any future charge can happen. The approval page must show:</p><ul><li>Merchant name</li><li>Amount or maximum amount</li><li>Currency</li><li>Billing frequency</li><li>Start date and expiry</li><li>Cancellation rights</li><li>Bank account or alias being used, masked where required</li></ul><p>Charges after approval do not require the customer to re-enter OTP every month unless the mandate rules, bank policy, or risk engine require step-up authorization.</p><h2 id="open-banking-security" tabindex="-1">Open Banking security <a class="header-anchor" href="#open-banking-security" aria-label="Permalink to &quot;Open Banking security&quot;">​</a></h2><p>Open Banking consent is OAuth-style. The hosted consent page must show the TPP or merchant name, the bank, selected accounts, requested scopes, duration, and purpose before approval.</p><p>Tokens are scoped. A token granted for <code>balances:read</code> must not read transactions. A token granted for one bank account must not access another account.</p><h2 id="webhook-security" tabindex="-1">Webhook security <a class="header-anchor" href="#webhook-security" aria-label="Permalink to &quot;Webhook security&quot;">​</a></h2><p>Treat webhooks as the final source for fulfilment, but verify them before trusting them:</p><ol><li>Use the raw request body.</li><li>Verify <code>X-OpenWave-Signature</code>.</li><li>Check timestamp freshness.</li><li>Deduplicate by event ID.</li><li>Persist before returning <code>2xx</code>.</li></ol><h2 id="bad-integration-patterns-to-reject" tabindex="-1">Bad integration patterns to reject <a class="header-anchor" href="#bad-integration-patterns-to-reject" aria-label="Permalink to &quot;Bad integration patterns to reject&quot;">​</a></h2><ul><li>Merchant frontend holds <code>mk_...</code> keys.</li><li>Merchant page collects bank OTP directly.</li><li>Open Banking scopes are hidden in a settings page instead of shown before consent.</li><li>Orders are fulfilled from browser callback parameters without webhook verification.</li><li>Production webhooks accept unsigned payloads.</li></ul>',19)])])}const b=t(o,[["render",i]]);export{p as __pageData,b as default};
